describe("DPO — golden vs StockCharts published formula", () => {
  it("matches the reference within 1e-6", () => {
    assertCloseArray(dpo(CLOSE, 20), DPO20, EPS, "DPO20");
  });
  it("NaN warmup prefix is exactly period-1", () => {
    expect(nanPrefixLength(dpo(CLOSE, 20))).toBe(19);
  });
  it("gotcha: a flat series -> 0 (price equals its own SMA)", () => {
    const flat = new Array(30).fill(7);
    const out = dpo(flat, 20);
    expect(out.slice(19).every((v) => Math.abs(v) < 1e-12)).toBe(true);
  });
  it("deterministic: same input -> identical output", () => {
    expectDeterministic(() => dpo(CLOSE, 20));
  });
});

describe("KST — golden vs Pring published formula", () => {
  it("KST line matches the reference within 1e-6", () => {
    assertCloseArray(kst(CLOSE).kst, KST, EPS, "KST");
  });
  it("signal line matches the reference within 1e-6", () => {
    assertCloseArray(kst(CLOSE).signal, KST_SIGNAL, EPS, "KST signal");
  });
  it("KST warmup prefix is 44; signal warmup is 52", () => {
    expect(nanPrefixLength(kst(CLOSE).kst)).toBe(44);
    expect(nanPrefixLength(kst(CLOSE).signal)).toBe(52);
  });
  it("gotcha: too-short series is all-NaN", () => {
    expect(kst(CLOSE.slice(0, 44)).kst.every(Number.isNaN)).toBe(true);
  });
  it("deterministic: same input -> identical output", () => {
    expectDeterministic(() => kst(CLOSE).kst);
  });
});

